def build_prefix(nums):
    prefix = [0] * (len(nums) + 1)
    for i in range(len(nums)):
        prefix[i + 1] = prefix[i] + nums[i]
    return prefix

def range_sum(prefix, l, r):
    return prefix[r + 1] - prefix[l]

nums = [3, 1, 4, 1, 5]
prefix = build_prefix(nums)
print(range_sum(prefix, 1, 3))  # 6

